13	-------------------------------------------------------------------------------
14	
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.std_logic_arith.all;
18	use ieee.std_logic_unsigned.all;
19	
20	library surf;
21	use surf.StdRtlPkg.all;
22	use surf.AxiLitePkg.all;
23	use surf.ArbiterPkg.all;
24	use surf.TextUtilPkg.all;
25	
26	entity AxiLiteCrossbar is
27	   generic (
28	      TPD_G              : time                             := 1 ns;
29	      RST_POLARITY_G     : sl                               := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
30	      RST_ASYNC_G        : boolean                          := false;
31	      NUM_SLAVE_SLOTS_G  : natural range 1 to 16            := 4;
32	      NUM_MASTER_SLOTS_G : natural range 1 to 64            := 4;
33	      DEC_ERROR_RESP_G   : slv(1 downto 0)                  := AXI_RESP_DECERR_C;
34	      MASTERS_CONFIG_G   : AxiLiteCrossbarMasterConfigArray := AXIL_XBAR_CFG_DEFAULT_C;
35	      DEBUG_G            : boolean                          := false);
36	   port (
37	      -- Clock and Reset
38	      axiClk    : in sl;
39	      axiClkRst : in sl;
40	
41	      -- Slave Slots (Connect to AxiLite Masters
42	      sAxiWriteMasters : in  AxiLiteWriteMasterArray(NUM_SLAVE_SLOTS_G-1 downto 0);
43	      sAxiWriteSlaves  : out AxiLiteWriteSlaveArray(NUM_SLAVE_SLOTS_G-1 downto 0);
44	      sAxiReadMasters  : in  AxiLiteReadMasterArray(NUM_SLAVE_SLOTS_G-1 downto 0);
45	      sAxiReadSlaves   : out AxiLiteReadSlaveArray(NUM_SLAVE_SLOTS_G-1 downto 0);
46	
47	      -- Master Slots (Connect to AXI Slaves)
48	      mAxiWriteMasters : out AxiLiteWriteMasterArray(NUM_MASTER_SLOTS_G-1 downto 0);
49	      mAxiWriteSlaves  : in  AxiLiteWriteSlaveArray(NUM_MASTER_SLOTS_G-1 downto 0);
50	      mAxiReadMasters  : out AxiLiteReadMasterArray(NUM_MASTER_SLOTS_G-1 downto 0);
51	      mAxiReadSlaves   : in  AxiLiteReadSlaveArray(NUM_MASTER_SLOTS_G-1 downto 0));
52	end entity AxiLiteCrossbar;
53	
54	architecture rtl of AxiLiteCrossbar is
55	
56	   function getHighAddr(config : AxiLiteCrossbarMasterConfigType) return slv is
57	      variable result : slv(31 downto 0);
58	   begin
59	      result := config.baseAddr;
60	      for k in 0 to config.addrBits - 1 loop
61	         result(k) := '1';
62	      end loop;
63	      return result;
64	   end function;
65	
66	   type SlaveStateType is (S_WAIT_AXI_TXN_S, S_DEC_ERR_S, S_ACK_S, S_TXN_S);
67	
68	   constant REQ_NUM_SIZE_C : integer := bitSize(NUM_MASTER_SLOTS_G-1);
69	   constant ACK_NUM_SIZE_C : integer := bitSize(NUM_SLAVE_SLOTS_G-1);
70	
71	   type SlaveType is record
72	      wrState  : SlaveStateType;
73	      wrReqs   : slv(NUM_MASTER_SLOTS_G-1 downto 0);
74	      wrReqNum : slv(REQ_NUM_SIZE_C-1 downto 0);
75	      rdState  : SlaveStateType;
76	      rdReqs   : slv(NUM_MASTER_SLOTS_G-1 downto 0);
77	      rdReqNum : slv(REQ_NUM_SIZE_C-1 downto 0);
78	   end record SlaveType;
79	
80	   type SlaveArray is array (natural range <>) of SlaveType;
81	
82	   type MasterStateType is (M_WAIT_REQ_S, M_WAIT_READYS_S, M_WAIT_REQ_FALL_S);
83	
84	   type MasterType is record
85	      wrState  : MasterStateType;
86	      wrAcks   : slv(NUM_SLAVE_SLOTS_G-1 downto 0);
87	      wrAckNum : slv(ACK_NUM_SIZE_C-1 downto 0);
88	      wrValid  : sl;
89	      rdState  : MasterStateType;
90	      rdAcks   : slv(NUM_SLAVE_SLOTS_G-1 downto 0);
91	      rdAckNum : slv(ACK_NUM_SIZE_C-1 downto 0);
92	      rdValid  : sl;
93	   end record MasterType;
94	
95	   type MasterArray is array (natural range <>) of MasterType;
96	
97	   type RegType is record
98	      slave            : SlaveArray(NUM_SLAVE_SLOTS_G-1 downto 0);
99	      master           : MasterArray(NUM_MASTER_SLOTS_G-1 downto 0);
100	      sAxiWriteSlaves  : AxiLiteWriteSlaveArray(NUM_SLAVE_SLOTS_G-1 downto 0);
101	      sAxiReadSlaves   : AxiLiteReadSlaveArray(NUM_SLAVE_SLOTS_G-1 downto 0);
102	      mAxiWriteMasters : AxiLiteWriteMasterArray(NUM_MASTER_SLOTS_G-1 downto 0);
103	      mAxiReadMasters  : AxiLiteReadMasterArray(NUM_MASTER_SLOTS_G-1 downto 0);
104	   end record RegType;
105	
106	   constant REG_INIT_C : RegType := (
107	      slave            => (
108	         others        => (
109	            wrState    => S_WAIT_AXI_TXN_S,
110	            wrReqs     => (others => '0'),
111	            wrReqNum   => (others => '0'),
112	            rdState    => S_WAIT_AXI_TXN_S,
113	            rdReqs     => (others => '0'),
114	            rdReqNum   => (others => '0'))),
115	      master           => (
116	         others        => (
117	            wrState    => M_WAIT_REQ_S,
118	            wrAcks     => (others => '0'),
119	            wrAckNum   => (others => '0'),
120	            wrValid    => '0',
121	            rdState    => M_WAIT_REQ_S,
122	            rdAcks     => (others => '0'),
123	            rdAckNum   => (others => '0'),
124	            rdValid    => '0')),
125	      sAxiWriteSlaves  => (others => AXI_LITE_WRITE_SLAVE_INIT_C),
126	      sAxiReadSlaves   => (others => AXI_LITE_READ_SLAVE_INIT_C),
127	      mAxiWriteMasters => axiWriteMasterInit(MASTERS_CONFIG_G),
128	      mAxiReadMasters  => axiReadMasterInit(MASTERS_CONFIG_G));
129	
130	   signal r   : RegType := REG_INIT_C;
131	   signal rin : RegType;
132	
133	   type AxiStatusArray is array (natural range <>) of AxiLiteStatusType;
134	
135	begin
136	
137	   assert (NUM_MASTER_SLOTS_G = MASTERS_CONFIG_G'length)
138	      report "Mismatch between NUM_MASTER_SLOTS_G and MASTERS_CONFIG_G'length"
139	      severity failure;
140	
141	   noneZeroCheck : for i in MASTERS_CONFIG_G'range generate
142	      assert (MASTERS_CONFIG_G(i).baseAddr(MASTERS_CONFIG_G(i).addrBits-1 downto 0) = 0)
143	         report "AXI_LITE_CROSSBAR Configuration Error:" & LF &
144	         "  - Array Index       : " & integer'image(i) & LF &
145	         "  - baseAddr          : 0x" & hstr(MASTERS_CONFIG_G(i).baseAddr) & LF &
146	         "  - addrBits          : " & str(MASTERS_CONFIG_G(i).addrBits) & LF &
147	         "  - connectivity      : 0x" & hstr(MASTERS_CONFIG_G(i).connectivity) & LF &
148	         "  => baseAddr must be zero within the specified addrBits range."
149	         severity failure;
150	   end generate noneZeroCheck;
151	
152	   gen_assert_master_config : for i in 0 to NUM_MASTER_SLOTS_G-1 generate
153	      gen_inner_loop : for j in 0 to NUM_MASTER_SLOTS_G-1 generate
154	         -- Ensure that no two master regions overlap
155	         assert (getHighAddr(MASTERS_CONFIG_G(i)) < MASTERS_CONFIG_G(j).baseAddr) or (getHighAddr(MASTERS_CONFIG_G(j)) < MASTERS_CONFIG_G(i).baseAddr) or (i = j)
156	            report "AXI_LITE_CROSSBAR Configuration Error:" & LF &
157	            "  - baseAddr(" & integer'image(i) & "): 0x" & hstr(MASTERS_CONFIG_G(i).baseAddr) & LF &
158	            "  - highAddr(" & integer'image(i) & "): 0x" & hstr(getHighAddr(MASTERS_CONFIG_G(i))) & LF &
159	            "  - baseAddr(" & integer'image(j) & "): 0x" & hstr(MASTERS_CONFIG_G(j).baseAddr) & LF &
160	            "  - highAddr(" & integer'image(j) & "): 0x" & hstr(getHighAddr(MASTERS_CONFIG_G(j))) & LF &
161	            "  => Address space overlap between master slot."
162	            severity failure;
163	      end generate;
164	   end generate;
165	
166	-- synopsys translate_off
167	   print(DEBUG_G, "AXI_LITE_CROSSBAR: " & LF &
168	         "NUM_SLAVE_SLOTS_G: " & integer'image(NUM_SLAVE_SLOTS_G) & LF &
169	         "NUM_MASTER_SLOTS_G: " & integer'image(NUM_MASTER_SLOTS_G) & LF &
170	         "DEC_ERROR_RESP_G: " & str(DEC_ERROR_RESP_G) & LF &
171	         "MASTERS_CONFIG_G:");
172	
173	   printCfg : for i in MASTERS_CONFIG_G'range generate
174	      print(DEBUG_G,
175	            "  baseAddr: " & hstr(MASTERS_CONFIG_G(i).baseAddr) & LF &
176	            "  addrBits: " & str(MASTERS_CONFIG_G(i).addrBits) & LF &
177	            "  connectivity: " & hstr(MASTERS_CONFIG_G(i).connectivity));
178	   end generate printCfg;
179	-- synopsys translate_on
180	
181	   comb : process (axiClkRst, mAxiReadSlaves, mAxiWriteSlaves, r,
182	                   sAxiReadMasters, sAxiWriteMasters) is
183	      variable v            : RegType;
184	      variable sAxiStatuses : AxiStatusArray(NUM_SLAVE_SLOTS_G-1 downto 0);
185	      variable mRdReqs      : slv(NUM_SLAVE_SLOTS_G-1 downto 0);
186	      variable mWrReqs      : slv(NUM_SLAVE_SLOTS_G-1 downto 0);
187	   begin
188	      v := r;
189	
190	      -- Control slave side outputs
191	      for s in NUM_SLAVE_SLOTS_G-1 downto 0 loop
192	
193	         v.sAxiWriteSlaves(s).awready := '0';
194	         v.sAxiWriteSlaves(s).wready  := '0';
195	         v.sAxiReadSlaves(s).arready  := '0';
196	
197	         -- Reset resp valid
198	         if (sAxiWriteMasters(s).bready = '1') then
199	            v.sAxiWriteSlaves(s).bvalid := '0';
200	         end if;
201	
202	         -- Reset rvalid upon rready
203	         if (sAxiReadMasters(s).rready = '1') then
204	            v.sAxiReadSlaves(s).rvalid := '0';
205	         end if;
206	
207	         -- Write state machine
208	         case (r.slave(s).wrState) is
209	            when S_WAIT_AXI_TXN_S =>
210	
211	               -- Incoming write
212	               if (sAxiWriteMasters(s).awvalid = '1' and sAxiWriteMasters(s).wvalid = '1') then
213	
214	                  for m in MASTERS_CONFIG_G'range loop
215	                     -- Check for address match
216	                     if ((MASTERS_CONFIG_G(m).addrBits = 32)
217	                         or (
218	                            StdMatch(  -- Use std_match to allow dontcares ('-')
219	                               sAxiWriteMasters(s).awaddr(31 downto MASTERS_CONFIG_G(m).addrBits),
220	                               MASTERS_CONFIG_G(m).baseAddr(31 downto MASTERS_CONFIG_G(m).addrBits))
221	                            and (MASTERS_CONFIG_G(m).connectivity(s) = '1')))
222	                     then
223	                        v.slave(s).wrReqs(m) := '1';
224	                        v.slave(s).wrReqNum  := conv_std_logic_vector(m, REQ_NUM_SIZE_C);
225	--                        print("AxiLiteCrossbar: Slave  " & str(s) & " reqd Master " & str(m) & " Write addr " & hstr(sAxiWriteMasters(s).awaddr));
226	                     end if;
227	                  end loop;
228	
229	                  -- Respond with error if decode fails
230	                  if (uOr(v.slave(s).wrReqs) = '0') then
231	                     v.sAxiWriteSlaves(s).awready := '1';
232	                     v.sAxiWriteSlaves(s).wready  := '1';
233	                     v.slave(s).wrState           := S_DEC_ERR_S;
234	                  else
235	                     v.slave(s).wrState := S_ACK_S;
236	                  end if;
237	               end if;
238	
239	            -- Send error
240	            when S_DEC_ERR_S =>
241	               -- Send error response
242	               v.sAxiWriteSlaves(s).bresp  := DEC_ERROR_RESP_G;
243	               v.sAxiWriteSlaves(s).bvalid := '1';
244	
245	               -- Clear when acked by master
246	               if (r.sAxiWriteSlaves(s).bvalid = '1' and sAxiWriteMasters(s).bready = '1') then
247	                  v.sAxiWriteSlaves(s).bvalid := '0';
248	                  v.slave(s).wrState          := S_WAIT_AXI_TXN_S;
249	               end if;
250	
251	            -- Transaction is acked
252	            when S_ACK_S =>
253	               for m in NUM_MASTER_SLOTS_G-1 downto 0 loop
254	                  if (r.slave(s).wrReqNum = m and r.slave(s).wrReqs(m) = '1' and r.master(m).wrAcks(s) = '1') then
255	                     v.sAxiWriteSlaves(s).awready := '1';
256	                     v.sAxiWriteSlaves(s).wready  := '1';
257	                     v.slave(s).wrState           := S_TXN_S;
258	                  end if;
259	               end loop;
260	
261	            -- Transaction in progress
262	            when S_TXN_S =>
263	               for m in NUM_MASTER_SLOTS_G-1 downto 0 loop
264	                  if (r.slave(s).wrReqNum = m and r.slave(s).wrReqs(m) = '1' and r.master(m).wrAcks(s) = '1') then
265	
266	                     -- Forward write response
267	                     v.sAxiWriteSlaves(s).bresp  := mAxiWriteSlaves(m).bresp;
268	                     v.sAxiWriteSlaves(s).bvalid := mAxiWriteSlaves(m).bvalid;
269	
270	                     -- bvalid or rvalid indicates txn concluding
271	                     if (r.sAxiWriteSlaves(s).bvalid = '1' and sAxiWriteMasters(s).bready = '1') then
272	                        v.sAxiWriteSlaves(s) := AXI_LITE_WRITE_SLAVE_INIT_C;
273	                        v.slave(s).wrReqs    := (others => '0');
274	                        v.slave(s).wrState   := S_WAIT_AXI_TXN_S;
275	                     end if;
276	                  end if;
277	               end loop;
278	            when others =>  -- For ASIC designs it is best to declare a 'Default' state which returns to S_WAIT_AXI_TXN_S state
279	               v := REG_INIT_C;
280	         end case;
281	
282	         -- Read state machine
283	         case (r.slave(s).rdState) is
284	            when S_WAIT_AXI_TXN_S =>
285	
286	               -- Incoming read
287	               if (sAxiReadMasters(s).arvalid = '1') then
288	                  for m in MASTERS_CONFIG_G'range loop
289	                     -- Check for address match
290	                     if ((MASTERS_CONFIG_G(m).addrBits = 32)
291	                         or (
292	                            StdMatch(  -- Use std_match to allow dontcares ('-')
293	                               sAxiReadMasters(s).araddr(31 downto MASTERS_CONFIG_G(m).addrBits),
294	                               MASTERS_CONFIG_G(m).baseAddr(31 downto MASTERS_CONFIG_G(m).addrBits))
295	                            and (MASTERS_CONFIG_G(m).connectivity(s) = '1')))
296	                     then
297	                        v.slave(s).rdReqs(m) := '1';
298	                        v.slave(s).rdReqNum  := conv_std_logic_vector(m, REQ_NUM_SIZE_C);
299	                     end if;
300	                  end loop;
301	
302	                  -- Respond with error if decode fails
303	                  if (uOr(v.slave(s).rdReqs) = '0') then
304	                     v.sAxiReadSlaves(s).arready := '1';
305	                     v.slave(s).rdState          := S_DEC_ERR_S;
306	                  else
307	                     v.slave(s).rdState := S_ACK_S;
308	                  end if;
309	               end if;
310	
311	            -- Error
312	            when S_DEC_ERR_S =>
313	               v.sAxiReadSlaves(s).rresp  := DEC_ERROR_RESP_G;
314	               v.sAxiReadSlaves(s).rdata  := (others => '0');
315	               v.sAxiReadSlaves(s).rvalid := '1';
316	
317	               if (r.sAxiReadSlaves(s).rvalid = '1' and sAxiReadMasters(s).rready = '1') then
318	                  v.sAxiReadSlaves(s).rvalid := '0';
319	                  v.slave(s).rdState         := S_WAIT_AXI_TXN_S;
320	               end if;
321	
322	            -- Transaction is acked
323	            when S_ACK_S =>
324	               for m in NUM_MASTER_SLOTS_G-1 downto 0 loop
325	                  if (r.slave(s).rdReqNum = m and r.slave(s).rdReqs(m) = '1' and r.master(m).rdAcks(s) = '1') then
326	                     v.sAxiReadSlaves(s).arready := '1';
327	                     v.slave(s).rdState          := S_TXN_S;
328	                  end if;
329	               end loop;
330	
331	            -- Transaction in progress
332	            when S_TXN_S =>
333	               for m in NUM_MASTER_SLOTS_G-1 downto 0 loop
334	                  if (r.slave(s).rdReqNum = m and r.slave(s).rdReqs(m) = '1' and r.master(m).rdAcks(s) = '1') then
335	
336	                     -- Forward read response
337	                     v.sAxiReadSlaves(s).rresp  := mAxiReadSlaves(m).rresp;
338	                     v.sAxiReadSlaves(s).rdata  := mAxiReadSlaves(m).rdata;
339	                     v.sAxiReadSlaves(s).rvalid := mAxiReadSlaves(m).rvalid;
340	
341	                     -- rvalid indicates txn concluding
342	                     if (r.sAxiReadSlaves(s).rvalid = '1' and sAxiReadMasters(s).rready = '1') then
343	                        v.sAxiReadSlaves(s) := AXI_LITE_READ_SLAVE_INIT_C;
344	                        v.slave(s).rdReqs   := (others => '0');
345	                        v.slave(s).rdState  := S_WAIT_AXI_TXN_S;  --S_WAIT_DONE_S;
346	                     end if;
347	                  end if;
348	               end loop;
349	            when others =>  -- For ASIC designs it is best to declare a 'Default' state which returns to S_WAIT_AXI_TXN_S state
350	               v := REG_INIT_C;
351	         end case;
352	      end loop;
353	
354	
355	      -- Control master side outputs
356	      for m in NUM_MASTER_SLOTS_G-1 downto 0 loop
357	
358	         -- Group reqs by master
359	         mWrReqs := (others => '0');
360	         mRdReqs := (others => '0');
361	         for i in mWrReqs'range loop
362	            mWrReqs(i) := r.slave(i).wrReqs(m);
363	            mRdReqs(i) := r.slave(i).rdReqs(m);
364	         end loop;
365	
366	         -- Write path processing
367	         case (r.master(m).wrState) is
368	            when M_WAIT_REQ_S =>
369	
370	               -- Keep these in reset state while waiting for requests
371	               v.master(m).wrAcks    := (others => '0');
372	               v.mAxiWriteMasters(m) := axiWriteMasterInit(MASTERS_CONFIG_G(m));
373	
374	               -- Wait for a request, arbitrate between simultaneous requests
375	               if (r.master(m).wrValid = '0') then
376	                  arbitrate(mWrReqs, r.master(m).wrAckNum, v.master(m).wrAckNum, v.master(m).wrValid, v.master(m).wrAcks);
377	               end if;
378	
379	               -- Upon valid request (set 1 cycle previous by arbitrate()), connect slave side
380	               -- buses to this master's outputs.
381	               if (r.master(m).wrValid = '1') then
382	                  v.master(m).wrAcks    := r.master(m).wrAcks;
383	                  v.mAxiWriteMasters(m) := sAxiWriteMasters(conv_integer(r.master(m).wrAckNum));
384	                  v.master(m).wrState   := M_WAIT_READYS_S;
385	               end if;
386	
387	            when M_WAIT_READYS_S =>
388	
389	               -- Wait for attached slave to respond
390	               -- Clear *valid signals upon *ready responses
391	               if (mAxiWriteSlaves(m).awready = '1') then
392	                  v.mAxiWriteMasters(m).awvalid := '0';
393	               end if;
394	               if (mAxiWriteSlaves(m).wready = '1') then
395	                  v.mAxiWriteMasters(m).wvalid := '0';
396	               end if;
397	
398	               -- When all *valid signals cleared, wait for slave side to clear request
399	               if (v.mAxiWriteMasters(m).awvalid = '0' and v.mAxiWriteMasters(m).wvalid = '0') then
400	                  v.master(m).wrState := M_WAIT_REQ_FALL_S;
401	               end if;
402	
403	            when M_WAIT_REQ_FALL_S =>
404	               -- When slave side deasserts request, clear ack and valid and start waiting for next
405	               -- request
406	               if (mWrReqs(conv_integer(r.master(m).wrAckNum)) = '0') then
407	                  v.master(m).wrState := M_WAIT_REQ_S;
408	                  v.master(m).wrAcks  := (others => '0');
409	                  v.master(m).wrValid := '0';
410	               end if;
411	
412	            when others =>  -- For ASIC designs it is best to declare a 'Default' state which returns to M_WAIT_REQ_S state
413	               v := REG_INIT_C;
414	         end case;
415	
416	         -- Don't allow baseAddr bits to be overwritten
417	         -- They can't be anyway based on the logic above, but Vivado can't figure that out.
418	         -- This helps optimization happen properly
419	         if (MASTERS_CONFIG_G(m).addrBits /= 32) then
420	            v.mAxiWriteMasters(m).awaddr(31 downto MASTERS_CONFIG_G(m).addrBits) :=
421	               MASTERS_CONFIG_G(m).baseAddr(31 downto MASTERS_CONFIG_G(m).addrBits);
422	         end if;
423	
424	
425	         -- Read path processing
426	         case (r.master(m).rdState) is
427	            when M_WAIT_REQ_S =>
428	
429	               -- Keep these in reset state while waiting for requests
430	               v.master(m).rdAcks   := (others => '0');
431	               v.mAxiReadMasters(m) := axiReadMasterInit(MASTERS_CONFIG_G(m));
432	
433	               -- Wait for a request, arbitrate between simultaneous requests
434	               if (r.master(m).rdValid = '0') then
435	                  arbitrate(mRdReqs, r.master(m).rdAckNum, v.master(m).rdAckNum, v.master(m).rdValid, v.master(m).rdAcks);
436	               end if;
437	
438	               -- Upon valid request (set 1 cycle previous by arbitrate()), connect slave side
439	               -- buses to this master's outputs.
440	               if (r.master(m).rdValid = '1') then
441	                  v.master(m).rdAcks   := r.master(m).rdAcks;
442	                  v.mAxiReadMasters(m) := sAxiReadMasters(conv_integer(r.master(m).rdAckNum));
443	                  v.master(m).rdState  := M_WAIT_READYS_S;
444	               end if;
445	
446	            when M_WAIT_READYS_S =>
447	
448	               -- Wait for attached slave to respond
449	               -- Clear *valid signals upon *ready responses
450	               if (mAxiReadSlaves(m).arready = '1') then
451	                  v.mAxiReadMasters(m).arvalid := '0';
452	               end if;
453	
454	               -- When all *valid signals cleared, wait for slave side to clear request
455	               if (v.mAxiReadMasters(m).arvalid = '0') then
456	                  v.master(m).rdState := M_WAIT_REQ_FALL_S;
457	               end if;
458	
459	            when M_WAIT_REQ_FALL_S =>
460	               -- When slave side deasserts request, clear ack and valid and start waiting for next
461	               -- request
462	               if (mRdReqs(conv_integer(r.master(m).rdAckNum)) = '0') then
463	                  v.master(m).rdState := M_WAIT_REQ_S;
464	                  v.master(m).rdAcks  := (others => '0');
465	                  v.master(m).rdValid := '0';
466	               end if;
467	
468	            when others =>  -- For ASIC designs it is best to declare a 'Default' state which returns to M_WAIT_REQ_S state
469	               v := REG_INIT_C;
470	         end case;
471	
472	         -- Don't allow baseAddr bits to be overwritten
473	         -- They can't be anyway based on the logic above, but Vivado can't figure that out.
474	         -- This helps optimization happen properly
475	         if (MASTERS_CONFIG_G(m).addrBits /= 32) then
476	            v.mAxiReadMasters(m).araddr(31 downto MASTERS_CONFIG_G(m).addrBits) :=
477	               MASTERS_CONFIG_G(m).baseAddr(31 downto MASTERS_CONFIG_G(m).addrBits);
478	         end if;
479	
480	      end loop;
481	
482	      if (RST_ASYNC_G = false and axiClkRst = RST_POLARITY_G) then
483	         v := REG_INIT_C;
484	      end if;
485	
486	      rin <= v;
487	
488	      sAxiReadSlaves   <= r.sAxiReadSlaves;
489	      sAxiWriteSlaves  <= r.sAxiWriteSlaves;
490	      mAxiReadMasters  <= r.mAxiReadMasters;
491	      mAxiWriteMasters <= r.mAxiWriteMasters;
492	
493	   end process comb;
494	
495	   seq : process (axiClk, axiClkRst) is
496	   begin
497	      if (RST_ASYNC_G and axiClkRst = RST_POLARITY_G) then
498	         r <= REG_INIT_C after TPD_G;
499	      elsif rising_edge(axiClk) then
500	         r <= rin after TPD_G;
501	      end if;
502	   end process seq;
503	
504	end architecture rtl;
505	
506

