25	   -------------------------------------------------------------------------------------------------
26	   -- AXI bus response codes
27	   -------------------------------------------------------------------------------------------------
28	   constant AXI_RESP_OK_C : slv(1 downto 0) := "00";  -- Access ok
29	
30	   constant AXI_RESP_EXOKAY_C : slv(1 downto 0) := "01";  -- Exclusive access ok
31	   -- Note: There are no "exclusive access" in AXI-Lite.  This is just a placeholder constant.
32	
33	   constant AXI_RESP_SLVERR_C : slv(1 downto 0) := "10";  -- Slave Error
34	   -- Note: A SLVERR response is returned to the master if the AXI peripheral interface receives any
35	   --       of the following unsupported accesses:
36	   --
37	   --          1) Any accesses with AWSIZE information other than 32-bit receives a SLVERR response.
38	   --          2) Any accesses with AWLEN information other than zero receives a SLVERR response.
39	   --          3) Any access that is unaligned, for example, where AWADDRP[1:0] is not equal to 2'b00,
40	   --             returns a SLVERR response where a read access returns all zeros and a write access
41	   --             does not modify the address location.
42	   --          4) Any write access that attempts to make use of the WSTRB lines,
43	   --             for example where any bits of WSTRB[3:0] are 0, returns a SLVERR response
44	   --             and does not modify the address location.
45	
46	   constant AXI_RESP_DECERR_C : slv(1 downto 0) := "11";  -- Decode Error
47	   -- Note: Any transaction that does not decode to a legal master interface destination,
48	   --       or programmers view register, receives a DECERR response. For an AHB master,
49	   --       the AXI DECERR is mapped back to an AHB ERROR.
