820	      -- Most significant data bus bit to be used in this recursion (max out at 31)
821	      constant BUS_HIGH_BIT_C  : integer := minimum(NORMAL_OFFSET_C+reg'length-1, 31);
822	
823	      constant STROBE_MASK_C : slv(3 downto 0) := genAxiSlaveStrobeMask(BUS_HIGH_BIT_C, NORMAL_OFFSET_C);
824	   begin
825	
826	      -- Read must come first so as not to overwrite the variable if read and write happen at once
