836	             std_match(ep.axiWriteMaster.wstrb, STROBE_MASK_C)) then
837	            -- if (constVal /= "X") then
838	            -- reg(REG_HIGH_BIT_C downto reg'low) := resize(constVal,(REG_HIGH_BIT_C-reg'low)+1);
839	            -- else
840	            reg(REG_HIGH_BIT_C downto reg'low) := ep.axiWriteMaster.wdata(BUS_HIGH_BIT_C downto NORMAL_OFFSET_C);
