940	      tmp(0) := reg;
941	      axiSlaveRegisterR(ep, addr, offset, tmp);
942	   end procedure;
943	
944	   procedure axiSlaveRegister (
945	      variable ep : inout AxiLiteEndpointType;
946	      addr        : in    slv;
947	      regs        : inout slv32Array)
948	   is
949	   begin
950	      for i in regs'range loop
951	         axiSlaveRegister(ep, slv(unsigned(addr) + to_unsigned(i*4, addr'length)), 0, regs(i));
952	      end loop;
953	
954	   end procedure;
955	
956	   procedure axiSlaveRegisterR (
957	      variable ep : inout AxiLiteEndpointType;
958	      addr        : in    slv;
959	      regs        : in    slv32Array)
960	   is
961	   begin
962	      for i in regs'range loop
963	         axiSlaveRegisterR(ep, slv(unsigned(addr) + to_unsigned(i*4, addr'length)), 0, regs(i));
964	      end loop;
965	
966	   end procedure;
967	
968	   procedure axiWrDetect (
969	      variable ep : inout AxiLiteEndpointType;
970	      addr        : in    slv;
971	      reg         : inout sl)
972	   is
973	      -- Need to remap addr range to be (length-1 downto 0)
974	      constant ADDR_LEN_C : integer                    := addr'length;
975	      constant ADDR_C     : slv(ADDR_LEN_C-1 downto 0) := addr;
976	   begin
977	      if (ep.axiStatus.writeEnable = '1') then
978	         if std_match(ep.axiWriteMaster.awaddr(ADDR_LEN_C-1 downto 2), ADDR_C(ADDR_LEN_C-1 downto 2)) then
979	            reg := '1';
980	            axiSlaveWriteResponse(ep.axiWriteSlave);
981	         end if;
982	      end if;
983	   end procedure;
984	
985	   procedure axiRdDetect (
986	      variable ep : inout AxiLiteEndpointType;
987	      addr        : in    slv;
988	      reg         : inout sl)
989	   is
990	      -- Need to remap addr range to be (length-1 downto 0)
991	      constant ADDR_LEN_C : integer                    := addr'length;
992	      constant ADDR_C     : slv(ADDR_LEN_C-1 downto 0) := addr;
993	   begin
994	      if (ep.axiStatus.readEnable = '1') then
995	         if std_match(ep.axiReadMaster.aRaddr(ADDR_LEN_C-1 downto 2), ADDR_C(ADDR_LEN_C-1 downto 2)) then
996	            reg := '1';
997	            axiSlaveReadResponse(ep.axiReadSlave);
998	         end if;
999	      end if;
1000	   end procedure;
1001	
1002	   procedure axiSlaveDefault (
1003	      variable ep            : inout AxiLiteEndpointType;
1004	      variable axiWriteSlave : inout AxiLiteWriteSlaveType;
1005	      variable axiReadSlave  : inout AxiLiteReadSlaveType;
1006	      axiResp                : in    slv(1 downto 0) := AXI_RESP_OK_C;
1007	      extTxn                 : in    sl              := '0') is
1008	   begin
1009	      if (ep.axiStatus.writeEnable = '1' and ep.axiWriteSlave.awready = '0' and extTxn = '0') then
1010	         axiSlaveWriteResponse(ep.axiWriteSlave, axiResp);
1011	      end if;
1012	
1013	      if (ep.axiStatus.readEnable = '1' and ep.axiReadSlave.arready = '0' and extTxn = '0') then
1014	         axiSlaveReadResponse(ep.axiReadSlave, axiResp);
1015	      end if;
1016	      axiWriteSlave := ep.axiWriteSlave;
1017	      axiReadSlave  := ep.axiReadSlave;
1018	   end procedure;
1019	
1020	
1021	   -------------------------------------------------------------------------------------------------
1022	   -- Slave AXI Processing functions
1023	   -------------------------------------------------------------------------------------------------
1024	
1025	   -- Generate evenly distributed address map
1026	   function genAxiLiteConfig (num      : positive;
1027	                              base     : slv(31 downto 0);
1028	                              baseBot  : integer range 1 to 32;
1029	                              addrBits : integer range 0 to 31)
1030	      return AxiLiteCrossbarMasterConfigArray is
1031	      variable retConf : AxiLiteCrossbarMasterConfigArray(num-1 downto 0);
1032	      variable addr    : slv(31 downto 0);
1033	   begin
1034	
1035	      -------------------------------------------------------------------------------------------
1036	      -- Note: These asserts only work in synthesis (not simulation)
1037	      -- https://forums.xilinx.com/t5/Synthesis/VHDL-assert-statement-within-function/td-p/413463
1038	      -------------------------------------------------------------------------------------------
1039	
1040	      -- Compare the baseBot to addrBits
1041	      assert (baseBot > addrBits)
1042	         report "AxiLitePkg.genAxiLiteConfig(): (baseBot > addrBits) condition not meet"
1043	         & lf & "num      = " & integer'image(num)
1044	         & lf & "base     = 0x" & hstr(base)
1045	         & lf & "baseBot  = " & integer'image(baseBot)
1046	         & lf & "addrBits = " & integer'image(addrBits)
1047	         severity failure;
1048	
1049	      -- Check that there is enough bits for the number of buses
1050	      assert (2**(baseBot-addrBits) >= num)
1051	         report "AxiLitePkg.genAxiLiteConfig(): (2**(baseBot-addrBits) >= num) condition not meet"
1052	         & lf & "num      = " & integer'image(num)
1053	         & lf & "base     = 0x" & hstr(base)
1054	         & lf & "baseBot  = " & integer'image(baseBot)
1055	         & lf & "addrBits = " & integer'image(addrBits)
1056	         severity failure;
1057	
1058	      -------------------------------------------------------------------------------------------
1059	      -- Init
1060	      -------------------------------------------------------------------------------------------
1061	      addr                     := base;
1062	      addr(baseBot-1 downto 0) := (others => '0');
1063	
1064	      -------------------------------------------------------------------------------------------
1065	      -- Generate records
1066	      -------------------------------------------------------------------------------------------
1067	      for i in 0 to num-1 loop
1068	         addr(baseBot-1 downto addrBits) := toSlv(i, baseBot-addrBits);
1069	         retConf(i).baseAddr             := addr;
1070	         retConf(i).addrBits             := addrBits;
1071	         retConf(i).connectivity         := x"FFFF";
1072	      end loop;
1073	
1074	      return retConf;
1075	   end function;
1076	
1077	   function genAxiSlaveStrobeMask (busHighBit : natural; normalOffset : natural) return slv is
1078	      variable strobeMask : slv(3 downto 0) := (others => '-');
1079	   begin
1080	      for i in busHighBit downto normalOffset loop
1081	         strobeMask(i/8) := '1';
1082	      end loop;
1083	      return strobeMask;
1084	   end function;
1085	
1086	   -------------------------------------------------------------------------------------------------
1087	   -- Simulation procedures
1088	   -------------------------------------------------------------------------------------------------
1089	
1090	   procedure axiLiteBusSimWrite (
1091	      signal axilClk         : in  sl;
1092	      signal axilWriteMaster : out AxiLiteWriteMasterType;
1093	      signal axilWriteSlave  : in  AxiLiteWriteSlaveType;
1094	      addr                   : in  slv(31 downto 0);
1095	      data                   : in  slv;
1096	      debug                  : in  boolean := false)
1097	   is
1098	      variable dataTmp : slv(31 downto 0);
1099	      variable addrTmp : slv(31 downto 0);
1100	   begin
1101	      dataTmp := resize(data, 32);
1102	
1103	      wait until axilClk = '1';
1104	      axilWriteMaster.awaddr  <= addr;
1105	      axilWriteMaster.wdata   <= dataTmp;
1106	      axilWriteMaster.awprot  <= (others => '0');
1107	      axilWriteMaster.wstrb   <= (others => '1');
1108	      axilWriteMaster.awvalid <= '1';
1109	      axilWriteMaster.wvalid  <= '1';
1110	      axilWriteMaster.bready  <= '1';
1111	
1112	
1113	      wait until axilClk = '1';
1114	      -- Wait for a response
1115	      while (axilWriteSlave.bvalid = '0') loop
1116	         -- Clear control signals when acked
1117	         if axilWriteSlave.awready = '1' then
1118	            axilWriteMaster.awvalid <= '0';
1119	         end if;
1120	         if axilWriteSlave.wready = '1' then
1121	            axilWriteMaster.wvalid <= '0';
1122	         end if;
1123	
1124	         wait until axilClk = '1';
1125	      end loop;
1126	
1127	      -- Clear control signals if bvalid and ready arrive at the same time
1128	      if axilWriteSlave.awready = '1' then
1129	         axilWriteMaster.awvalid <= '0';
1130	      end if;
1131	      if axilWriteSlave.wready = '1' then
1132	         axilWriteMaster.wvalid <= '0';
1133	      end if;
1134	
1135	      -- Done. Check for errors
1136	      axilWriteMaster.bready <= '0';
1137	
1138	      print(debug, "AxiLitePkg::axiLiteBusSimWrite(addr:" & hstr(addr) & ", data: " & hstr(dataTmp) & ")");
1139	      if (axilWriteSlave.bresp = AXI_RESP_SLVERR_C) then
1140	         report "AxiLitePkg::axiLiteBusSimWrite( addr:" & hstr(addr) & "): - BRESP = SLAVE_ERROR" severity warning;
1141	      elsif (axilWriteSlave.bresp = AXI_RESP_DECERR_C) then
1142	         report "AxiLitePkg::axiLiteBusSimWrite( addr:" & hstr(addr) & "): BRESP = DECODE_ERROR" severity warning;
1143	      end if;
1144	
1145	
1146	      -- If data size is greater than 32, make a recursive call to write the next word
1147	      if (data'length > 32) then
1148	         addrTmp := slv(unsigned(addr) + 4);
1149	         axiLiteBusSimWrite(axilClk, axilWriteMaster, axilWriteSlave, addrTmp, data(data'high downto 32), debug);
1150	      end if;
1151	
1152	   end procedure axiLiteBusSimWrite;
1153	
1154	
1155	   procedure axiLiteBusSimRead (
1156	      signal axilClk        : in  sl;
1157	      signal axilReadMaster : out AxiLiteReadMasterType;
1158	      signal axilReadSlave  : in  AxiLiteReadSlaveType;
1159	      addr                  : in  slv(31 downto 0);
1160	      data                  : out slv;
1161	      debug                 : in  boolean := false)
1162	   is
1163	      variable dataTmp : slv(31 downto 0);
1164	      variable addrTmp : slv(31 downto 0);
1165	   begin
1166	      -- Put the write req on the bus
1167	      wait until axilClk = '1';
1168	      axilReadMaster.araddr  <= addr;
1169	      axilReadMaster.arprot  <= (others => '0');
1170	      axilReadMaster.arvalid <= '1';
1171	      axilReadMaster.rready  <= '1';
1172	
1173	      wait until axilClk = '1';
1174	      -- Wait for a response
1175	      while (axilReadSlave.rvalid = '0') loop
1176	         -- Clear control signals when acked
1177	         if axilReadSlave.arready = '1' then
1178	            axilReadMaster.arvalid <= '0';
1179	         end if;
1180	
1181	         wait until axilClk = '1';
1182	      end loop;
1183	
1184	      -- Clear control signals when acked
1185	      if axilReadSlave.arready = '1' then
1186	         axilReadMaster.arvalid <= '0';
1187	      end if;
1188	
1189	      -- Done. Check for errors
1190	      if (axilReadSlave.rresp = AXI_RESP_SLVERR_C) then
1191	         report "AxiLitePkg::axiLiteBusSimRead( addr:" & hstr(addr) & "): RRESP = SLAVE_ERROR" severity warning;
1192	      elsif (axilReadSlave.rresp = AXI_RESP_DECERR_C) then
1193	         report "AxiLitePkg::axiLiteBusSimRead( addr:" & hstr(addr) & "): RRESP = DECODE_ERROR" severity warning;
1194	      else
1195	         dataTmp := axilReadSlave.rdata;
1196	         print(debug, "AxiLitePkg::axiLiteBusSimRead( addr:" & hstr(addr) & ", data: " & hstr(axilReadSlave.rdata) & ")");
1197	      end if;
1198	      axilReadMaster.rready <= '0';
1199	
1200	      if (data'length > 32) then
1201	         addrTmp                           := slv(unsigned(addr) + 4);
1202	         data(data'low+31 downto data'low) := dataTmp;
1203	         axiLiteBusSimRead(axilClk, axilReadMaster, axilReadSlave, addrTmp, data(data'high downto 32), debug);
1204	      else
1205	         data := resize(dataTmp, data'length);
1206	      end if;
1207	
1208	
1209	   end procedure axiLiteBusSimRead;
1210	
1211	   function ite (i : boolean; t : AxiLiteReadMasterType; e : AxiLiteReadMasterType) return AxiLiteReadMasterType is
1212	   begin
1213	      if (i) then return t; else return e; end if;
1214	   end function ite;
1215	
1216	   function ite (i : boolean; t : AxiLiteReadSlaveType; e : AxiLiteReadSlaveType) return AxiLiteReadSlaveType is
1217	   begin
1218	      if (i) then return t; else return e; end if;
1219	   end function ite;
1220	
1221	   function ite (i : boolean; t : AxiLiteWriteMasterType; e : AxiLiteWriteMasterType) return AxiLiteWriteMasterType is
1222	   begin
1223	      if (i) then return t; else return e; end if;
1224	   end function ite;
1225	
1226	   function ite (i : boolean; t : AxiLiteWriteSlaveType; e : AxiLiteWriteSlaveType) return AxiLiteWriteSlaveType is
1227	   begin
1228	      if (i) then return t; else return e; end if;
1229	   end function ite;
1230	
1231	
1232	end package body AxiLitePkg;
1233	
1234

